import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './TopWorstSellers.css';
import Optionbar from "./Optionbar";

const TopWorstSellers = () => {
    const [items, setItems] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError]     = useState(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [sortOrder, setSortOrder]   = useState('top');

    useEffect(() => {
        const fetchData = async () => {
            try {
                // Haal verkoopcijfers
                const res = await axios.get('http://localhost:3007/api/sales', { withCredentials: true });
                setItems(res.data);
            } catch (err) {
                console.error(err);
                setError('Kon verkoopcijfers niet laden');
            } finally {
                setLoading(false);
            }
        };
        fetchData();
    }, []);

    if (loading) return <p>Loading…</p>;
    if (error)   return <p className="error">{error}</p>;

    // Sorteer op aantal verkocht
    const sorted = [...items].sort((a, b) => {
        return sortOrder === 'top' ? b.sold_count - a.sold_count
            : a.sold_count - b.sold_count;
    });

    // Filter op zoekterm
    const filtered = sorted.filter(item =>
        item.item_name.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="top-worst-container">
            <div className="centre-content">
                <div className="section-header">
                    <h2>Top & Worst Sellers</h2>
                    <div>
                        <button
                            className={sortOrder === 'top' ? 'active' : ''}
                            onClick={() => setSortOrder('top')}
                        >
                            Top ↑
                        </button>
                        <button
                            className={sortOrder === 'worst' ? 'active' : ''}
                            onClick={() => setSortOrder('worst')}
                        >
                            Worst ↓
                        </button>
                    </div>
                    <input
                        type="text"
                        placeholder="Search"
                        value={searchTerm}
                        onChange={e => setSearchTerm(e.target.value)}
                    />
                </div>
                <ul className="items-list">
                    {filtered.map((item, idx) => (
                        <li key={item.id_menu_item} className="item">
                            <span>{idx + 1}. {item.item_name}</span>
                            <span className="item-count">{item.sold_count} sold</span>
                        </li>
                    ))}
                </ul>
            </div>
            <Optionbar title="Segments" />
        </div>
    );
};

export default TopWorstSellers;
